import { useState } from "react";
import { ExternalLink, Heart, Truck, Shield, Check } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { cn } from "@/lib/utils";
import type { Product } from "@shared/schema";

interface ProductQuickViewProps {
  product: Product | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function ProductQuickView({
  product,
  open,
  onOpenChange,
}: ProductQuickViewProps) {
  const [isFavorite, setIsFavorite] = useState(false);
  const [isImageLoaded, setIsImageLoaded] = useState(false);

  if (!product) return null;

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("de-DE", {
      style: "currency",
      currency: "EUR",
    }).format(price);
  };

  const isInStock = product.availability === "in stock";
  const hasDiscount =
    product.strikePrice && product.strikePrice > product.priceBrutto;
  const discountPercent = hasDiscount
    ? Math.round((1 - product.priceBrutto / product.strikePrice!) * 100)
    : 0;

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl p-0 gap-0 overflow-hidden" data-testid="dialog-quickview">
        <div className="grid md:grid-cols-2">
          {/* Bildbereich */}
          <div className="relative aspect-square md:aspect-auto bg-secondary/30">
            {!isImageLoaded && (
              <div className="absolute inset-0 shimmer" />
            )}
            <img
              src={product.imageUrl}
              alt={product.title}
              loading="lazy"
              onLoad={() => setIsImageLoaded(true)}
              className={cn(
                "w-full h-full object-cover",
                isImageLoaded ? "opacity-100" : "opacity-0"
              )}
              data-testid="img-quickview-product"
            />
            {hasDiscount && (
              <Badge
                variant="destructive"
                className="absolute top-4 left-4 text-sm"
                data-testid="badge-quickview-discount"
              >
                -{discountPercent}%
              </Badge>
            )}
          </div>

          {/* Inhalt */}
          <div className="p-6 flex flex-col">
            <DialogHeader className="text-left mb-4">
              <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1" data-testid="text-quickview-category">
                {product.category}
              </p>
              <DialogTitle className="text-xl font-semibold text-foreground leading-tight" data-testid="text-quickview-title">
                {product.title.split("»")[0].trim()}
              </DialogTitle>
            </DialogHeader>

            {/* Preis */}
            <div className="flex items-baseline gap-3 mb-4">
              <span className="text-2xl font-bold text-foreground" data-testid="text-quickview-price">
                {formatPrice(product.priceBrutto)}
              </span>
              {hasDiscount && (
                <span className="text-lg text-muted-foreground line-through" data-testid="text-quickview-original-price">
                  {formatPrice(product.strikePrice!)}
                </span>
              )}
            </div>

            {/* Verfügbarkeit */}
            <div className="flex items-center gap-2 mb-4" data-testid="container-quickview-availability">
              {isInStock ? (
                <>
                  <Check className="h-4 w-4 text-green-600" />
                  <span className="text-sm text-green-600 font-medium" data-testid="text-quickview-instock">
                    Auf Lager
                  </span>
                </>
              ) : (
                <span className="text-sm text-muted-foreground" data-testid="text-quickview-outofstock">
                  Derzeit nicht verfügbar
                </span>
              )}
            </div>

            <Separator className="my-4" />

            {/* Beschreibung */}
            <div className="flex-1 overflow-y-auto mb-6">
              <p className="text-sm text-muted-foreground line-clamp-6" data-testid="text-quickview-description">
                {product.description}
              </p>
            </div>

            {/* Vorteile */}
            <div className="space-y-2 mb-6">
              <div className="flex items-center gap-2 text-sm text-muted-foreground" data-testid="text-quickview-shipping">
                <Truck className="h-4 w-4 text-primary" />
                <span>
                  {product.shippingCost && product.shippingCost > 0
                    ? `Versand: ${formatPrice(product.shippingCost)}`
                    : "Kostenloser Versand"}
                </span>
              </div>
              <div className="flex items-center gap-2 text-sm text-muted-foreground" data-testid="text-quickview-secure">
                <Shield className="h-4 w-4 text-primary" />
                <span>Sichere Bezahlung</span>
              </div>
            </div>

            {/* Aktionen */}
            <div className="flex gap-3">
              <a
                href={product.deeplink}
                target="_blank"
                rel="noopener noreferrer"
                className="flex-1"
                data-testid="link-quickview-offer"
              >
                <Button className="w-full gap-2" size="lg" data-testid="button-quickview-buy">
                  Zum Angebot
                  <ExternalLink className="h-4 w-4" />
                </Button>
              </a>
              <Button
                variant="outline"
                size="lg"
                onClick={() => setIsFavorite(!isFavorite)}
                data-testid="button-quickview-favorite"
              >
                <Heart
                  className={cn(
                    "h-5 w-5",
                    isFavorite && "fill-destructive text-destructive"
                  )}
                />
              </Button>
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/ui/button.tsx.content:
import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0" +
  " hover-elevate active-elevate-2",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground border border-primary-border",
        destructive:
          "bg-destructive text-destructive-foreground border border-destructive-border",
        outline:
          // Shows the background color of whatever card / sidebar / accent background it is inside of.
          // Inherits the current text color.
          " border [border-color:var(--button-outline)]  shadow-xs active:shadow-none ",
        secondary: "border bg-secondary text-secondary-foreground border border-secondary-border ",
        // Add a transparent border so that when someone toggles a border on later, it doesn't shift layout/size.
        ghost: "border border-transparent",
      },
      // Heights are set as "min" heights, because sometimes Ai will place large amount of content
      // inside buttons. With a min-height they will look appropriate with small amounts of content,
      // but will expand to fit large amounts of content.
      size: {
        default: "min-h-9 px-4 py-2",
        sm: "min-h-8 rounded-md px-3 text-xs",
        lg: "min-h-10 rounded-md px-8",
        icon: "h-9 w-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  },
)
Button.displayName = "Button"

export { Button, buttonVariants }

client/src/components/product-card.tsx.content:
import { useState } from "react";
import { ExternalLink, Heart, Eye, GitCompare } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { useShop } from "@/contexts/shop-context";
import { useToast } from "@/hooks/use-toast";
import type { Product } from "@shared/schema";

interface ProductCardProps {
  product: Product;
  index?: number;
  onQuickView?: (product: Product) => void;
}

export function ProductCard({ product, index = 0, onQuickView }: ProductCardProps) {
  const [isImageLoaded, setIsImageLoaded] = useState(false);
  const [isHovered, setIsHovered] = useState(false);
  const { toggleWishlist, isInWishlist, toggleCompare, isInCompare, canAddMoreToCompare } = useShop();
  const { toast } = useToast();

  const isFavorite = isInWishlist(product.id);
  const isComparing = isInCompare(product.id);

  const formatPrice = (price: number) => {
    return new Intl.NumberFormat("de-DE", {
      style: "currency",
      currency: "EUR",
    }).format(price);
  };

  // Produkt ist verfügbar wenn deliveryTime nicht "nicht lieferbar" enthält
  const isInStock = !product.deliveryTime?.toLowerCase().includes("nicht lieferbar");
  const hasDiscount = product.strikePrice && product.strikePrice > product.priceBrutto;
  const discountPercent = hasDiscount
    ? Math.round((1 - product.priceBrutto / product.strikePrice!) * 100)
    : 0;

  return (
    <Card
      className={cn(
        "group relative overflow-visible border-card-border bg-card transition-all duration-300 hover-elevate",
        "animate-fade-in",
        index <= 7 && `stagger-${index + 1}`
      )}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      data-testid={`card-product-${product.id}`}
    >
      {/* Bildbereich */}
      <div className="relative aspect-product overflow-hidden rounded-t-md bg-secondary/30">
        {/* Lade-Shimmer */}
        {!isImageLoaded && (
          <div className="absolute inset-0 shimmer" />
        )}

        {/* Produktbild */}
        <img
          src={product.imageUrl}
          alt={product.title}
          loading="lazy"
          onLoad={() => setIsImageLoaded(true)}
          className={cn(
            "w-full h-full object-cover transition-all duration-500",
            isImageLoaded ? "opacity-100" : "opacity-0",
            isHovered && "scale-105"
          )}
        />

        {/* Badges */}
        <div className="absolute top-2 left-2 flex flex-col gap-1">
          {hasDiscount && (
            <Badge variant="destructive" className="text-xs font-medium">
              -{discountPercent}%
            </Badge>
          )}
          {!isInStock && (
            <Badge variant="secondary" className="text-xs">
              Ausverkauft
            </Badge>
          )}
        </div>

        {/* Aktionsbuttons */}
        <div
          className={cn(
            "absolute top-2 right-2 flex flex-col gap-1 transition-all duration-200",
            isHovered ? "opacity-100 translate-x-0" : "opacity-0 translate-x-2"
          )}
          style={{ visibility: isHovered ? "visible" : "hidden" }}
        >
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="secondary"
                size="icon"
                className="h-8 w-8 bg-background/90 backdrop-blur-sm"
                onClick={(e) => {
                  e.preventDefault();
                  toggleWishlist(product.id);
                  toast({
                    title: isFavorite ? "Von Merkliste entfernt" : "Zur Merkliste hinzugefügt",
                    duration: 2000,
                  });
                }}
                data-testid={`button-favorite-${product.id}`}
              >
                <Heart
                  className={cn(
                    "h-4 w-4 transition-colors",
                    isFavorite && "fill-destructive text-destructive"
                  )}
                />
              </Button>
            </TooltipTrigger>
            <TooltipContent side="left">
              {isFavorite ? "Von Merkliste entfernen" : "Zur Merkliste"}
            </TooltipContent>
          </Tooltip>
          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="secondary"
                size="icon"
                className={cn(
                  "h-8 w-8 bg-background/90 backdrop-blur-sm",
                  isComparing && "ring-2 ring-primary"
                )}
                onClick={(e) => {
                  e.preventDefault();
                  if (!isComparing && !canAddMoreToCompare) {
                    toast({
                      title: "Vergleichsliste voll",
                      description: "Maximal 4 Produkte können verglichen werden",
                      variant: "destructive",
                      duration: 2000,
                    });
                    return;
                  }
                  toggleCompare(product.id);
                  toast({
                    title: isComparing ? "Vom Vergleich entfernt" : "Zum Vergleich hinzugefügt",
                    duration: 2000,
                  });
                }}
                data-testid={`button-compare-${product.id}`}
              >
                <GitCompare
                  className={cn(
                    "h-4 w-4 transition-colors",
                    isComparing && "text-primary"
                  )}
                />
              </Button>
            </TooltipTrigger>
            <TooltipContent side="left">
              {isComparing ? "Vom Vergleich entfernen" : "Zum Vergleich"}
            </TooltipContent>
          </Tooltip>
          {onQuickView && (
            <Tooltip>
              <TooltipTrigger asChild>
                <Button
                  variant="secondary"
                  size="icon"
                  className="h-8 w-8 bg-background/90 backdrop-blur-sm"
                  onClick={(e) => {
                    e.preventDefault();
                    onQuickView(product);
                  }}
                  data-testid={`button-quickview-${product.id}`}
                >
                  <Eye className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent side="left">Schnellansicht</TooltipContent>
            </Tooltip>
          )}
        </div>

        {/* Schnellansicht Overlay */}
        <div
          className={cn(
            "absolute inset-x-0 bottom-0 p-3 bg-gradient-to-t from-black/60 to-transparent transition-all duration-200",
            isHovered ? "opacity-100 translate-y-0" : "opacity-0 translate-y-2"
          )}
          style={{ visibility: isHovered ? "visible" : "hidden" }}
        >
          <a
            href={product.deeplink}
            target="_blank"
            rel="noopener noreferrer"
            className="block"
          >
            <Button
              size="sm"
              className="w-full gap-2 bg-white text-black hover:bg-white/90"
              data-testid={`button-view-${product.id}`}
            >
              Zum Angebot
              <ExternalLink className="h-3 w-3" />
            </Button>
          </a>
        </div>
      </div>

      {/* Inhalt */}
      <CardContent className="p-4">
        {/* Kategorie */}
        <p className="text-xs text-muted-foreground uppercase tracking-wide mb-1">
          {product.category}
        </p>

        {/* Titel */}
        <h3 className="font-medium text-sm line-clamp-2 mb-2 min-h-[2.5rem] text-foreground">
          {product.title.split("»")[0].trim()}
        </h3>

        {/* Preis */}
        <div className="flex items-baseline gap-2">
          <span className="text-lg font-semibold text-foreground" data-testid={`text-price-${product.id}`}>
            {formatPrice(product.priceBrutto)}
          </span>
          {hasDiscount && (
            <span className="text-sm text-muted-foreground line-through">
              {formatPrice(product.strikePrice!)}
            </span>
          )}
        </div>

        {/* Versand */}
        {product.shippingCost !== undefined && (
          <p className="text-xs text-muted-foreground mt-1">
            {product.shippingCost > 0
              ? `+ ${formatPrice(product.shippingCost)} Versand`
              : "Kostenloser Versand"}
          </p>
        )}
      </CardContent>
    </Card>
  );
}

export function ProductCardSkeleton() {
  return (
    <Card className="overflow-hidden border-card-border">
      <div className="aspect-product shimmer" />
      <CardContent className="p-4 space-y-3">
        <div className="h-3 w-16 shimmer rounded" />
        <div className="space-y-2">
          <div className="h-4 shimmer rounded" />
          <div className="h-4 w-3/4 shimmer rounded" />
        </div>
        <div className="h-5 w-20 shimmer rounded" />
      </CardContent>
    </Card>
  );
}

