  --primary: 20 80% 55%;
  --primary-foreground: 0 0% 100%;
  --secondary: 20 12% 20%;
  --secondary-foreground: 30 15% 90%;
  --muted: 20 10% 22%;
  --muted-foreground: 30 10% 60%;
  --accent: 25 18% 22%;
  --accent-foreground: 30 15% 95%;
  --destructive: 0 72% 51%;
  --destructive-foreground: 0 0% 100%;
  --input: 20 12% 30%;
  --ring: 20 80% 55%;
  --chart-1: 20 80% 55%;
  --chart-2: 35 60% 60%;
  --chart-3: 180 55% 55%;
  --chart-4: 280 45% 60%;
  --chart-5: 140 50% 55%;
  --shadow-2xs: 0px 1px 2px 0px hsl(0 0% 0% / 0.10);
  --shadow-xs: 0px 1px 3px 0px hsl(0 0% 0% / 0.12);
  --shadow-sm: 0px 2px 4px 0px hsl(0 0% 0% / 0.12), 0px 1px 2px -1px hsl(0 0% 0% / 0.12);
  --shadow: 0px 4px 6px -1px hsl(0 0% 0% / 0.15), 0px 2px 4px -2px hsl(0 0% 0% / 0.15);
  --shadow-md: 0px 6px 10px -2px hsl(0 0% 0% / 0.18), 0px 3px 6px -3px hsl(0 0% 0% / 0.18);
  --shadow-lg: 0px 10px 15px -3px hsl(0 0% 0% / 0.20), 0px 4px 6px -4px hsl(0 0% 0% / 0.20);
  --shadow-xl: 0px 20px 25px -5px hsl(0 0% 0% / 0.25), 0px 8px 10px -6px hsl(0 0% 0% / 0.25);
  --shadow-2xl: 0px 25px 50px -12px hsl(0 0% 0% / 0.40);

  --sidebar-primary-border: hsl(var(--sidebar-primary));
  --sidebar-primary-border: hsl(from hsl(var(--sidebar-primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --sidebar-accent-border: hsl(var(--sidebar-accent));
  --sidebar-accent-border: hsl(from hsl(var(--sidebar-accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --primary-border: hsl(var(--primary));
  --primary-border: hsl(from hsl(var(--primary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --secondary-border: hsl(var(--secondary));
  --secondary-border: hsl(from hsl(var(--secondary)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --muted-border: hsl(var(--muted));
  --muted-border: hsl(from hsl(var(--muted)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --accent-border: hsl(var(--accent));
  --accent-border: hsl(from hsl(var(--accent)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);

  --destructive-border: hsl(var(--destructive));
  --destructive-border: hsl(from hsl(var(--destructive)) h s calc(l + var(--opaque-button-border-intensity)) / alpha);
}

@layer base {
  * {
    @apply border-border;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    @apply font-sans antialiased bg-background text-foreground;
  }
}

@layer utilities {
  /* Hide ugly search cancel button in Chrome */
  input[type="search"]::-webkit-search-cancel-button {
    @apply hidden;
  }

  /* Placeholder styling for contentEditable div */
  [contenteditable][data-placeholder]:empty::before {
    content: attr(data-placeholder);
    color: hsl(var(--muted-foreground));
    pointer-events: none;
  }

  /* Escape hatches for default elevations */
  .no-default-hover-elevate {}
  .no-default-active-elevate {}

  /* Toggle elevate system */
  .toggle-elevate::before,
  .toggle-elevate-2::before {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: -1;
  }

  .toggle-elevate.toggle-elevated::before {
    background-color: var(--elevate-2);
  }

  .border.toggle-elevate::before {
    inset: -1px;
  }

  /* Hover/Active elevate system */
  .hover-elevate:not(.no-default-hover-elevate),
  .active-elevate:not(.no-default-active-elevate),
  .hover-elevate-2:not(.no-default-hover-elevate),
  .active-elevate-2:not(.no-default-active-elevate) {
    position: relative;
    z-index: 0;
  }

  .hover-elevate:not(.no-default-hover-elevate)::after,
  .active-elevate:not(.no-default-active-elevate)::after,
  .hover-elevate-2:not(.no-default-hover-elevate)::after,
  .active-elevate-2:not(.no-default-active-elevate)::after {
    content: "";
    pointer-events: none;
    position: absolute;
    inset: 0px;
    border-radius: inherit;
    z-index: 999;
  }

  .hover-elevate:hover:not(.no-default-hover-elevate)::after,
  .active-elevate:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-1);
  }

  .hover-elevate-2:hover:not(.no-default-hover-elevate)::after,
  .active-elevate-2:active:not(.no-default-active-elevate)::after {
    background-color: var(--elevate-2);
  }

  .border.hover-elevate:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate:not(.no-active-interaction-elevate)::after,
  .border.hover-elevate-2:not(.no-hover-interaction-elevate)::after,
  .border.active-elevate-2:not(.no-active-interaction-elevate)::after {
    inset: -1px;
  }

  /* Premium text gradient */
  .text-gradient {
    @apply bg-gradient-to-r from-primary to-primary/70 bg-clip-text text-transparent;
  }

  /* Shimmer animation for loading states */
  @keyframes shimmer {
    0% {
      background-position: -200% 0;
    }
    100% {
      background-position: 200% 0;
    }
  }

  .shimmer {
    background: linear-gradient(
      90deg,
      hsl(var(--muted)) 0%,
      hsl(var(--muted) / 0.5) 50%,
      hsl(var(--muted)) 100%
    );
    background-size: 200% 100%;
    animation: shimmer 1.5s infinite;
  }

  /* Fade in animation */
  @keyframes fadeIn {
    from {
      opacity: 0;
      transform: translateY(10px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  .animate-fade-in {
    animation: fadeIn 0.4s ease-out forwards;
  }

  /* Stagger animation delay */
  .stagger-1 { animation-delay: 50ms; }
  .stagger-2 { animation-delay: 100ms; }
  .stagger-3 { animation-delay: 150ms; }
  .stagger-4 { animation-delay: 200ms; }
  .stagger-5 { animation-delay: 250ms; }
  .stagger-6 { animation-delay: 300ms; }
  .stagger-7 { animation-delay: 350ms; }
  .stagger-8 { animation-delay: 400ms; }

  /* Hide scrollbar but keep functionality */
  .hide-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }
  .hide-scrollbar::-webkit-scrollbar {
    display: none;
  }

  /* Product image aspect ratio */
  .aspect-product {
    aspect-ratio: 4 / 3;
  }

  /* Line clamp utilities */
  .line-clamp-2 {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .line-clamp-3 {
    display: -webkit-box;
    -webkit-line-clamp: 3;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  /* GPU-accelerated transforms for smooth animations */
  .gpu-accelerate {
    transform: translateZ(0);
    will-change: transform, opacity;
    backface-visibility: hidden;
  }

  /* Floating animation for decorative elements */
  @keyframes float {
    0%, 100% { transform: translateY(0px) rotate(0deg); }
    25% { transform: translateY(-8px) rotate(1deg); }
    50% { transform: translateY(-4px) rotate(0deg); }
    75% { transform: translateY(-10px) rotate(-1deg); }
  }

  .animate-float {
    animation: float 6s ease-in-out infinite;
  }

  .animate-float-delayed {
    animation: float 6s ease-in-out infinite;
    animation-delay: 2s;
  }

  /* Pulse glow effect */
  @keyframes pulse-glow {
    0%, 100% { 
      box-shadow: 0 0 20px hsl(var(--primary) / 0.3), 0 0 40px hsl(var(--primary) / 0.1);
    }
    50% { 
      box-shadow: 0 0 30px hsl(var(--primary) / 0.5), 0 0 60px hsl(var(--primary) / 0.2);
    }
  }

  .animate-pulse-glow {
    animation: pulse-glow 3s ease-in-out infinite;
  }

  /* Slide up reveal animation */
  @keyframes slideUpReveal {
    from {
      opacity: 0;
      transform: translateY(40px);
    }
    to {
      opacity: 1;
      transform: translateY(0);
    }
  }

  .animate-slide-up {
    animation: slideUpReveal 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  }

  /* Scale in animation */
  @keyframes scaleIn {
    from {
      opacity: 0;
      transform: scale(0.9);
    }
    to {
      opacity: 1;
      transform: scale(1);
    }
  }

  .animate-scale-in {
    animation: scaleIn 0.5s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  }

  /* Parallax scroll effect placeholder */
  .parallax-slow {
    will-change: transform;
  }

  /* Gradient text animation */
  @keyframes gradient-shift {
    0%, 100% { background-position: 0% 50%; }
    50% { background-position: 100% 50%; }
  }

  .animate-gradient-text {
    background: linear-gradient(
      90deg,
      hsl(var(--primary)) 0%,
      hsl(20 90% 60%) 25%,
      hsl(var(--primary)) 50%,
      hsl(25 85% 55%) 75%,
      hsl(var(--primary)) 100%
    );
    background-size: 200% auto;
    background-clip: text;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    animation: gradient-shift 4s ease infinite;
  }

  /* Shine effect on hover */
  .shine-effect {
    position: relative;
    overflow: hidden;
  }

  .shine-effect::before {
    content: "";
    position: absolute;
    top: 0;
    left: -100%;
    width: 50%;
    height: 100%;
    background: linear-gradient(
      90deg,
      transparent,
      rgba(255, 255, 255, 0.3),
      transparent
    );
    transform: skewX(-25deg);
    transition: left 0.5s ease;
  }

  .shine-effect:hover::before {
    left: 150%;
  }

  /* Card lift effect */
  .card-lift {
    transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.3s ease;
  }

  .card-lift:hover {
    transform: translateY(-8px) scale(1.02);
    box-shadow: 0 20px 40px -15px hsl(var(--primary) / 0.2);
  }

  /* Blur load effect for images */
  .blur-load {
    filter: blur(10px);
    transition: filter 0.5s ease;
  }

  .blur-load.loaded {
    filter: blur(0);
  }

  /* Ripple effect on click */
  @keyframes ripple {
    to {
      transform: scale(4);
      opacity: 0;
    }
  }

  .ripple-effect {
    position: relative;
    overflow: hidden;
  }

  .ripple-effect::after {
    content: "";
    position: absolute;
    width: 100px;
    height: 100px;
    background: hsl(var(--primary) / 0.3);
    border-radius: 50%;
    transform: scale(0);
    opacity: 1;
    pointer-events: none;
  }

  .ripple-effect:active::after {
    animation: ripple 0.6s linear;
  }

  /* Gradient border animation */
  @keyframes border-gradient {
    0%, 100% { border-color: hsl(var(--primary)); }
    25% { border-color: hsl(25 80% 55%); }
    50% { border-color: hsl(30 75% 50%); }
    75% { border-color: hsl(15 85% 55%); }
  }

  .animate-border-gradient {
    animation: border-gradient 4s ease infinite;
  }

  /* Text reveal animation */
  @keyframes textReveal {
    0% {
      clip-path: polygon(0 0, 0 0, 0 100%, 0 100%);
    }
    100% {
      clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);
    }
  }

  .animate-text-reveal {
    animation: textReveal 0.8s cubic-bezier(0.77, 0, 0.175, 1) forwards;
  }

  /* Stagger delays for wow effects */
  .wow-1 { animation-delay: 0ms; }
  .wow-2 { animation-delay: 100ms; }
  .wow-3 { animation-delay: 200ms; }
  .wow-4 { animation-delay: 300ms; }
  .wow-5 { animation-delay: 400ms; }
  .wow-6 { animation-delay: 500ms; }

  /* Glass morphism effect */
  .glass {
    background: hsl(var(--background) / 0.7);
    backdrop-filter: blur(12px);
    -webkit-backdrop-filter: blur(12px);
    border: 1px solid hsl(var(--border) / 0.3);
  }

  .glass-dark {
    background: hsl(0 0% 0% / 0.5);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
  }

  /* Gradient overlay for hero */
  .hero-gradient {
    background: linear-gradient(
      135deg,
      hsl(var(--primary) / 0.9) 0%,
      hsl(20 70% 40% / 0.8) 50%,
      hsl(0 0% 0% / 0.7) 100%
    );
  }

  /* Decorative blur circles */
  .blur-circle {
    position: absolute;
    border-radius: 50%;
    filter: blur(60px);
    opacity: 0.5;
    pointer-events: none;
  }

  .blur-circle-primary {
    background: hsl(var(--primary) / 0.4);
  }

  .blur-circle-accent {
    background: hsl(25 80% 60% / 0.3);
  }

  /* ============================================
     SPECTACULAR HERO INTRO ANIMATIONS
     ============================================ */

  /* Floating particles animation */
  @keyframes float-particle {
    0%, 100% {
      transform: translateY(0) translateX(0) scale(1);
      opacity: 0;
    }
    10% {
      opacity: 0.8;
    }
    50% {
      transform: translateY(-100px) translateX(20px) scale(1.2);
      opacity: 0.4;
    }
    90% {
      opacity: 0.6;
    }
  }

  .animate-float-particle {
    animation: float-particle 8s ease-in-out infinite;
  }

  /* Slow pulse for glow orbs */
  @keyframes pulse-slow {
    0%, 100% {
      transform: scale(1);
      opacity: 0.3;
    }
    50% {
      transform: scale(1.2);
      opacity: 0.5;
    }
  }

  .animate-pulse-slow {
    animation: pulse-slow 6s ease-in-out infinite;
  }

  /* Shimmer gradient animation */
  @keyframes shimmer {
    0% {
      background-position: -200% 0;
    }
    100% {
      background-position: 200% 0;
    }
  }

  .animate-shimmer {
    animation: shimmer 3s linear infinite;
  }

  /* Cursor blink animation */
  @keyframes blink {
    0%, 50% { opacity: 1; }
    51%, 100% { opacity: 0; }
  }

  .animate-blink {
    animation: blink 1s step-end infinite;
  }

  /* Grid movement animation */
  @keyframes grid-move {
    0% {
      transform: translate(0, 0);
    }
    100% {
      transform: translate(60px, 60px);
    }
  }

  /* Dramatic text reveal */
  @keyframes dramatic-reveal {
    0% {
      opacity: 0;
      transform: translateY(60px) rotateX(-15deg);
      filter: blur(10px);
    }
    100% {
      opacity: 1;
      transform: translateY(0) rotateX(0);
      filter: blur(0);
    }
  }

  .animate-dramatic-reveal {
    animation: dramatic-reveal 1s cubic-bezier(0.16, 1, 0.3, 1) forwards;
  }

  /* Glow pulse animation */
  @keyframes glow-pulse {
    0%, 100% {
      box-shadow: 0 0 20px hsl(var(--primary) / 0.3), 0 0 40px hsl(var(--primary) / 0.2);
    }
    50% {
      box-shadow: 0 0 30px hsl(var(--primary) / 0.5), 0 0 60px hsl(var(--primary) / 0.3);
    }
  }

  .animate-glow-pulse {
    animation: glow-pulse 2s ease-in-out infinite;
  }

  /* Magnetic hover effect */
  .magnetic-hover {
    transition: transform 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  .magnetic-hover:hover {
    transform: scale(1.05);
  }

  /* Cinematic vignette */
  .cinematic-vignette::after {
    content: "";
    position: absolute;
    inset: 0;
    background: radial-gradient(ellipse at center, transparent 0%, transparent 50%, rgba(0,0,0,0.5) 100%);
    pointer-events: none;
  }

  /* Spotlight effect */
  @keyframes spotlight {
    0%, 100% {
      opacity: 0.3;
      transform: translate(-50%, -50%) scale(1);
    }
    50% {
      opacity: 0.5;
      transform: translate(-50%, -50%) scale(1.1);
    }
  }

  .spotlight {
    position: absolute;
    width: 150%;
    height: 150%;
    background: radial-gradient(ellipse at center, hsl(var(--primary) / 0.15) 0%, transparent 60%);
    animation: spotlight 8s ease-in-out infinite;
    pointer-events: none;
  }

  /* Glass morphism enhanced */
  .glass {
    background: rgba(255, 255, 255, 0.08);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(255, 255, 255, 0.1);
  }

  .dark .glass {
    background: rgba(0, 0, 0, 0.3);
    border: 1px solid rgba(255, 255, 255, 0.08);
  }

  /* Hover scale with glow */
  .hover-glow-scale {
    transition: all 0.3s cubic-bezier(0.34, 1.56, 0.64, 1);
  }

  .hover-glow-scale:hover {
    transform: scale(1.05);
    box-shadow: 0 10px 40px hsl(var(--primary) / 0.3);
  }

  /* Text gradient with animation */
  .text-gradient-animate {
    background: linear-gradient(
      90deg,
      hsl(var(--primary)),
      hsl(35 100% 60%),
      hsl(var(--primary))
    );
    background-size: 200% auto;
    background-clip: text;
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    animation: shimmer 3s linear infinite;
  }

  /* Bounce in animation */
  @keyframes bounce-in {
    0% {
      opacity: 0;
      transform: scale(0.3) translateY(50px);
    }
    50% {
      transform: scale(1.05) translateY(-10px);
    }
    70% {
      transform: scale(0.95) translateY(0);
    }
    100% {
      opacity: 1;
      transform: scale(1) translateY(0);
    }
  }

  .animate-bounce-in {
    animation: bounce-in 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55) forwards;
  }

  /* Parallax depth layers */
  .parallax-layer-1 {
    transform: translateZ(-2px) scale(3);
  }

  .parallax-layer-2 {
    transform: translateZ(-1px) scale(2);
  }

  /* Neon glow text */
  .neon-glow {
    text-shadow: 
      0 0 10px hsl(var(--primary) / 0.8),
      0 0 20px hsl(var(--primary) / 0.6),
      0 0 40px hsl(var(--primary) / 0.4),
      0 0 80px hsl(var(--primary) / 0.2);
  }

  /* Morphing background */
  @keyframes morph-bg {
    0%, 100% {
      border-radius: 60% 40% 30% 70% / 60% 30% 70% 40%;
    }
    50% {
      border-radius: 30% 60% 70% 40% / 50% 60% 30% 60%;
    }
  }

  .morph-bg {
    animation: morph-bg 8s ease-in-out infinite;
  }

  /* Floating animation enhanced */
  @keyframes float-enhanced {
    0%, 100% {
      transform: translateY(0px) rotate(0deg);
    }
    25% {
      transform: translateY(-15px) rotate(2deg);
    }
    75% {
      transform: translateY(-5px) rotate(-2deg);
    }
  }

  .animate-float-enhanced {
    animation: float-enhanced 6s ease-in-out infinite;
  }

  /* GPU acceleration for smooth animations */
  .gpu-accelerate {
    transform: translateZ(0);
    backface-visibility: hidden;
    perspective: 1000px;
  }
}

